class Solution {
    public TreeNode expTree(String s) {
        Stack<TreeNode> nodes = new Stack<>();
        Stack<Character> ops = new Stack<>();
        for (int i = 0; i < s.length(); ++i) {
            if (Character.isDigit(s.charAt(i))) {
                nodes.push(new TreeNode(s.charAt(i)));
            } else if (s.charAt(i) == '(') {
                ops.push(s.charAt(i));
            } else if (s.charAt(i) == ')') {
                while (ops.peek() != '(') {
                    process(nodes, ops);
                }
                ops.pop();
            } else {
                while (!ops.empty() && precedence(ops.peek(), s.charAt(i))) {
                    process(nodes, ops);
                }
                ops.push(s.charAt(i));
            }
        }
        while (!ops.empty()) {
            process(nodes, ops);
        }
        return nodes.peek();
    }

    private boolean precedence(char a, char b) {
        if (a == '(') return false;
        if (b == '(' || b == ')') return true;
        if ((a == '*' || a == '/') && (b == '+' || b == '-')) return true;
        return false;
    }

    private void process(Stack<TreeNode> nodes, Stack<Character> ops) {
        TreeNode right = nodes.pop();
        TreeNode left = nodes.pop();
        TreeNode oper = new TreeNode(ops.pop());
        oper.left = left;
        oper.right = right;
        nodes.push(oper);
    }
}
